const data = $input.first().json;
const clientId = data.client_id;
const date = data.date;

// Check if daily_metrics row already exists for this client + date
const existing = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://bfzdcyuyilesubtgbhdc.supabase.co/rest/v1/daily_metrics?client_id=eq.${clientId}&date=eq.${date}&select=id,ad_spend,ad_impressions,ad_clicks`,
  headers: {
    'apikey': $env.SUPABASE_API_KEY,
    'Authorization': `Bearer ${$env.SUPABASE_API_KEY}`
  }
});

const adPayload = {
  ad_spend: data.ad_spend || 0,
  ad_impressions: data.ad_impressions || 0,
  ad_clicks: data.ad_clicks || 0
};

if (existing && existing.length > 0) {
  // PATCH existing record
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `https://bfzdcyuyilesubtgbhdc.supabase.co/rest/v1/daily_metrics?id=eq.${existing[0].id}`,
    headers: {
      'apikey': $env.SUPABASE_API_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_API_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: adPayload
  });
} else {
  // POST new record with ad data
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://bfzdcyuyilesubtgbhdc.supabase.co/rest/v1/daily_metrics`,
    headers: {
      'apikey': $env.SUPABASE_API_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_API_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: {
      client_id: clientId,
      date: date,
      new_leads: 0,
      hot_leads: 0,
      avg_lead_score: 0,
      agent_actions: 0,
      total_conversations: 0,
      ...adPayload
    }
  });
}

return [{
  json: {
    client_id: clientId,
    date: date,
    action: existing && existing.length > 0 ? 'updated' : 'created',
    ...adPayload
  }
}];
